    parsed_redirect_uri = urlparse(redirect_uri)
    
    # Ensure the scheme and netloc match, and the redirect_uri starts with the registered_uri
    return (parsed_registered_uri.scheme == parsed_redirect_uri.scheme and
            parsed_registered_uri.netloc == parsed_redirect_uri.netloc and
            redirect_uri.startswith(registered_uri))

